package com.example.prodapi.controller;

import com.example.prodapi.service.GreetingService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/api")
public class GreetingController {

    private static final Logger logger = LoggerFactory.getLogger(GreetingController.class);
    private final GreetingService greetingService;

    public GreetingController(GreetingService greetingService) {
        this.greetingService = greetingService;
        logger.info("GreetingController initialized.");
    }

    @GetMapping("/greet")
    public ResponseEntity<String> greet(@RequestParam(value = "name", defaultValue = "World") String name) {
        logger.info("Received GET request to /api/greet with name: {}", name);

        try {
            String greeting = greetingService.getGreeting(name);
            logger.info("Successfully processed greeting for name: {}. Response: {}", name, greeting);
            return ResponseEntity.ok(greeting);
        } catch (Exception e) {
            logger.error("Error processing greeting for name: {}", name, e);
            return ResponseEntity.internalServerError().body("An error occurred while generating greeting.");
        }
    }
}
