package com.example.prodapi.service;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

@Service
public class GreetingService {

    private static final Logger logger = LoggerFactory.getLogger(GreetingService.class);

    public GreetingService() {
        logger.info("GreetingService initialized.");
    }

    public String getGreeting(String name) {
        logger.debug("Entering getGreeting method with name: {}", name); // Example of debug logging for internal flow
        String greetingMessage = String.format("Hello, %s! Welcome to our Production API.", name);
        logger.info("Successfully generated greeting message for name: {}", name); // Successful operation log
        logger.debug("Exiting getGreeting method.");
        return greetingMessage;
    }
}
